eval (() => {
  const articles = document.querySelectorAll('article.Box-row');
  const results = [];
  for (let i = 0; i < 3; i++) {
    const art = articles[i];
    const name = art.querySelector('h2 a')?.textContent?.trim().replace(/\s+/g, ' ');
    const href = art.querySelector('h2 a')?.getAttribute('href');
    const desc = art.querySelector('p.col-9')?.textContent?.trim();
    const lang = art.querySelector('[itemprop="programmingLanguage"]')?.textContent?.trim();
    const stars = art.querySelector('a[href$="/stargazers"]')?.textContent?.trim().replace(/\s+/g, '');
    const starsToday = art.querySelector('.d-inline-block.float-sm-right')?.textContent?.trim().replace(/\s+/g, ' ');
    results.push({ rank: i+1, name, href, desc, lang, stars, starsToday });
  }
  return JSON.stringify(results, null, 2);
})()

eval (() => {
  const art = document.querySelectorAll('article.Box-row')[0];
  // Try all possible language selectors
  const allSpans = [...art.querySelectorAll('span')].map(s => s.className + ': ' + s.textContent.trim());
  return JSON.stringify(allSpans.filter(s => s.length < 120));
})()
